import * as React from "react";

import {
  type DateRange as DayPickerDateRange,
  DayPicker,
} from "react-day-picker";

import { Button } from "../button";
import { CalendarIcon } from "../icons";
import { Popover, PopoverContent, PopoverTrigger } from "../popover";
import { cn } from "../utils/cn";

type DateRange = {
  from?: Date;
  to?: Date;
};

type DateRangePickerProps = {
  range?: DateRange;
  onRangeChange?: (range: DateRange | undefined) => void;
  placeholder?: string;
  disabled?: boolean;
  className?: string;
};

const calendarClassNames = {
  root: "text-foreground",
  months: "flex gap-4",
  month: "space-y-4",
  month_caption: "flex justify-center pt-1 relative items-center",
  caption_label: "text-sm font-medium",
  nav: "flex items-center gap-1",
  button_previous:
    "inline-flex items-center justify-center rounded-sm h-7 w-7 bg-transparent hover:bg-surface text-foreground",
  button_next:
    "inline-flex items-center justify-center rounded-sm h-7 w-7 bg-transparent hover:bg-surface text-foreground",
  month_grid: "w-full border-collapse space-y-1",
  weekdays: "flex",
  weekday: "text-muted-foreground rounded-sm w-9 font-normal text-[0.8rem]",
  week: "flex w-full mt-2",
  day: "h-9 w-9 text-center text-sm relative flex items-center justify-center rounded-sm hover:bg-surface",
  day_button: "h-9 w-9 p-0 font-normal inline-flex items-center justify-center",
  selected:
    "bg-primary text-primary-foreground hover:bg-primary hover:text-primary-foreground",
  range_start: "rounded-r-none",
  range_end: "rounded-l-none",
  range_middle: "bg-primary/20 text-foreground rounded-none",
  today: "font-bold",
  outside: "text-muted-foreground opacity-50",
  disabled: "text-muted-foreground opacity-50",
};

function formatRange(range: DateRange): string {
  if (range.from && range.to) {
    return `${range.from.toLocaleDateString()} – ${range.to.toLocaleDateString()}`;
  }
  if (range.from) {
    return range.from.toLocaleDateString();
  }
  return "";
}

/**
 * A date range picker that composes Popover, Button, and react-day-picker v9
 * with side-by-side dual calendars for selecting a date range.
 */
function DateRangePicker({
  range,
  onRangeChange,
  placeholder = "Pick a date range",
  disabled = false,
  className,
}: DateRangePickerProps) {
  const [open, setOpen] = React.useState(false);

  const displayText = range?.from ? formatRange(range) : placeholder;

  function handleSelect(selected: DayPickerDateRange | undefined) {
    onRangeChange?.(
      selected ? { from: selected.from, to: selected.to } : undefined,
    );
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <div data-slot="date-range-picker" className={cn(className)}>
        <PopoverTrigger asChild>
          <Button
            variant="solid"
            color="default"
            disabled={disabled}
            className={cn(
              "justify-start text-left font-normal",
              !range?.from && "text-muted-foreground",
            )}
          >
            <CalendarIcon />
            <span>{displayText}</span>
          </Button>
        </PopoverTrigger>
        <PopoverContent className="w-auto p-3" align="start">
          <DayPicker
            mode="range"
            selected={
              range?.from ? { from: range.from, to: range.to } : undefined
            }
            onSelect={handleSelect}
            numberOfMonths={2}
            classNames={calendarClassNames}
          />
        </PopoverContent>
      </div>
    </Popover>
  );
}

export { DateRangePicker };
export type { DateRange, DateRangePickerProps };
